{
  "intent_summary": "Assess breadth of relmora distribution/coverage by counting active campus accounts (relmora_total_mg > 0) and total shipped volume over the most recent 52 weeks of available data, at the national level (no campus grouping).",
  "tables": [
    "data_867"
  ],
  "filters": [
    {
      "column": "week_end_date",
      "operator": ">=",
      "value": "derived:rolling_window_52_weeks_from_max_week_end_date"
    },
    {
      "column": "week_end_date",
      "operator": "<=",
      "value": "derived:max_week_end_date"
    },
    {
      "column": "relmora_total_mg",
      "operator": ">",
      "value": 0
    }
  ],
  "aggregations": [
    {
      "metric_name": "active_campus_accounts_52w",
      "function": "COUNT",
      "column": "campus_id",
      "group_level": "none"
    },
    {
      "metric_name": "sales_mg_52w",
      "function": "SUM",
      "column": "relmora_total_mg",
      "group_level": "none"
    }
  ],
  "subqueries": [
    {
      "name": "max_week_end_date_cte",
      "purpose": "Identify the most recent week_end_date available in data_867 to anchor rolling windows.",
      "logic": "Compute MAX(week_end_date) from data_867 and expose as max_week_end_date."
    },
    {
      "name": "rolling_52w_window_bounds",
      "purpose": "Define explicit start and end boundaries for the last 52 weeks based on max_week_end_date.",
      "logic": "Set window_end_date = max_week_end_date; set window_start_date_52w = (max_week_end_date - 51 weeks) aligned to week_end_date-based weeks."
    },
    {
      "name": "active_accounts_filter_logic",
      "purpose": "Ensure breadth/account status metrics consider only records with positive relmora volume.",
      "logic": "For breadth/account counting and any account status metrics, include only rows where relmora_total_mg > 0; count DISTINCT campus_id after applying the 52-week date window."
    }
  ],
  "group_by": [],
  "order_by": [],
  "limit": null,
  "final_output": {
    "columns": [
      "window_start_date_52w",
      "window_end_date_52w",
      "active_campus_accounts_52w",
      "sales_mg_52w"
    ],
    "row_granularity": "single_row"
  },
  "validation_rules": [
    "Use only data_867 for this request.",
    "Default time period to the most recent 52 weeks when user does not specify a time window.",
    "Determine the latest available period using MAX(week_end_date); do not use system date.",
    "Rolling 52-week window must be anchored to max_week_end_date; window_start_date_52w = max_week_end_date minus 51 weeks; window_end_date_52w = max_week_end_date.",
    "Breadth/account ordering status metrics must consider only records where relmora_total_mg > 0 and must count DISTINCT campus_id.",
    "Use relmora_total_mg (not relmora_total_sls) because the question is not about market share or competitor comparisons.",
    "Because the request is not explicitly campus-level output, do not group by campus_id or campus_account_name; return a national single-row summary.",
    "Output must explicitly include the time window boundaries (start and end dates) for the 52-week period."
  ],
  "rag_alignment": {
    "rag_provided": true,
    "used_examples": [
      "Example #1"
    ],
    "borrowed_patterns": [
      "Breadth defined as count of active campus accounts (distinct campus_id with relmora_total_mg > 0) plus total relmora volume over a rolling 52-week window anchored to MAX(week_end_date)",
      "National-level single-row output with explicit 52-week window start and end dates"
    ],
    "differences_from_examples": []
  }
}

{
  "intent_summary": "Assess revenue dependency by measuring each campus region's contribution to total national Relmora sales over the most recent 52 weeks of available data, and provide concentration indicators (top 1/2/3 regions).",
  "tables": [
    "data_867"
  ],
  "filters": [
    {
      "column": "week_end_date",
      "operator": ">=",
      "value": "derived:rolling_window_52_weeks_from_max_week_end_date"
    },
    {
      "column": "week_end_date",
      "operator": "<=",
      "value": "derived:max_week_end_date"
    }
  ],
  "aggregations": [
    {
      "metric_name": "region_sales_52w",
      "function": "SUM",
      "column": "relmora_total_mg",
      "group_level": "campus_region"
    },
    {
      "metric_name": "nation_sales_52w",
      "function": "SUM",
      "column": "relmora_total_mg",
      "group_level": "none"
    }
  ],
  "subqueries": [
    {
      "name": "max_week_end_date_cte",
      "purpose": "Identify the most recent week_end_date in the dataset to anchor the default 52-week window.",
      "logic": "Compute MAX(week_end_date) from data_867 and expose it as max_week_end_date."
    },
    {
      "name": "time_window_cte",
      "purpose": "Define the default analysis window and its boundaries.",
      "logic": "Set window_end_date = max_week_end_date; set window_start_date = window_end_date minus 51 weeks (inclusive 52-week span)."
    },
    {
      "name": "region_agg_cte",
      "purpose": "Aggregate 52-week sales by campus_region.",
      "logic": "Filter rows to [window_start_date, window_end_date] using week_end_date; group by campus_region; compute SUM(relmora_total_mg) as region_sales_52w."
    },
    {
      "name": "nation_agg_cte",
      "purpose": "Aggregate 52-week national sales across all regions for denominator.",
      "logic": "Filter rows to [window_start_date, window_end_date] using week_end_date; compute SUM(relmora_total_mg) as nation_sales_52w."
    },
    {
      "name": "contribution_cte",
      "purpose": "Compute each region's contribution percent of national sales and concentration ranking.",
      "logic": "Join region_agg_cte to nation_agg_cte (cross join); compute region_contribution_52w = (region_sales_52w / nation_sales_52w) * 100; convert to integer (no decimals) before output and append '%' in label; compute region_rank by region_sales_52w descending (ties broken deterministically by campus_region ascending)."
    },
    {
      "name": "concentration_summary_cte",
      "purpose": "Provide overall concentration indicators to determine dependency on a few regions.",
      "logic": "From contribution_cte compute top_1_region_contribution_52w as contribution where region_rank=1; top_2_regions_contribution_52w as sum of contributions where region_rank<=2; top_3_regions_contribution_52w as sum of contributions where region_rank<=3; convert all to integer (no decimals) and append '%' in label."
    }
  ],
  "group_by": [
    "campus_region"
  ],
  "order_by": [
    {
      "column": "region_sales_52w",
      "direction": "DESC"
    }
  ],
  "limit": 10,
  "final_output": {
    "columns": [
      "window_start_date",
      "window_end_date",
      "campus_region",
      "region_sales_52w",
      "nation_sales_52w",
      "region_contribution_52w%",
      "region_rank",
      "top_1_region_contribution_52w%",
      "top_2_regions_contribution_52w%",
      "top_3_regions_contribution_52w%"
    ],
    "row_granularity": "per_group"
  },
  "validation_rules": [
    "Use data_867 as the only source table for this question.",
    "Use relmora_total_mg (not relmora_total_sls) because the question is about relmora dependency without explicit market share or competitor comparison request.",
    "Default time window is the most recent 52 weeks of available data when the user does not specify a period.",
    "Derive max_week_end_date using MAX(week_end_date); do not use system date; do not use MAX(month_year) or MAX(quarter_year).",
    "Output must explicitly include window_start_date and window_end_date.",
    "Region contribution must use national total (all rows in the window) as denominator and must be expressed with a trailing '%'.",
    "Also include the corresponding absolute sales values alongside contribution metrics (region_sales_52w and nation_sales_52w).",
    "Order regions by region_sales_52w descending to highlight concentration; limit output to top 10 regions.",
    "All computations related to percentage values must be converted to integers (no decimals) before output, and include the '%' symbol in the label."
  ],
  "rag_alignment": {
    "rag_provided": true,
    "used_examples": [
      "Example #1"
    ],
    "borrowed_patterns": [
      "Default to most recent 52 weeks anchored to MAX(week_end_date)",
      "Group by campus_region and compute region SUM(relmora_total_mg) plus national SUM(relmora_total_mg) as denominator",
      "Compute region contribution % and rank regions by sales",
      "Provide concentration metrics for top 1/2/3 regions"
    ],
    "differences_from_examples": []
  }
}

{
  "intent_summary": "Produce a weekly sales trend for the most recent 52 weeks with one row per week_end_date and sales by area plus national total presented as separate columns.",
  "tables": [
    "data_867"
  ],
  "filters": [
    {
      "column": "relmora_total_mg",
      "operator": ">",
      "value": 0
    },
    {
      "column": "week_end_date",
      "operator": ">=",
      "value": "derived:rolling_window"
    }
  ],
  "aggregations": [
    {
      "metric_name": "sales_central",
      "function": "SUM",
      "column": "relmora_total_mg",
      "group_level": "week_end_date"
    },
    {
      "metric_name": "sales_great_lakes",
      "function": "SUM",
      "column": "relmora_total_mg",
      "group_level": "week_end_date"
    },
    {
      "metric_name": "sales_north_east",
      "function": "SUM",
      "column": "relmora_total_mg",
      "group_level": "week_end_date"
    },
    {
      "metric_name": "sales_mid_atlantic",
      "function": "SUM",
      "column": "relmora_total_mg",
      "group_level": "week_end_date"
    },
    {
      "metric_name": "sales_south_east",
      "function": "SUM",
      "column": "relmora_total_mg",
      "group_level": "week_end_date"
    },
    {
      "metric_name": "sales_nation",
      "function": "SUM",
      "column": "relmora_total_mg",
      "group_level": "week_end_date"
    }
  ],
  "subqueries": [
    {
      "name": "max_week_end_date_cte",
      "purpose": "Identify the most recent week_end_date in the dataset to anchor the rolling 52-week window.",
      "logic": "Compute MAX(week_end_date) from data_867; expose as a single scalar column max_week_end_date."
    },
    {
      "name": "base_last52w",
      "purpose": "Restrict rows to the most recent 52 weeks relative to the dataset's max_week_end_date and exclude non-positive sales.",
      "logic": "Cross join data_867 to max_week_end_date_cte; filter relmora_total_mg > 0 and week_end_date between (max_week_end_date - 51 weeks) and max_week_end_date, inclusive."
    },
    {
      "name": "weekly_pivot_sales",
      "purpose": "Compute weekly sales with area (mapped to campus_region) in columns plus national total.",
      "logic": "From base_last52w group by week_end_date; compute sales_central = SUM(CASE WHEN campus_region = 'Central' THEN relmora_total_mg ELSE 0 END), sales_great_lakes = SUM(CASE WHEN campus_region = 'Great Lakes' THEN relmora_total_mg ELSE 0 END), sales_north_east = SUM(CASE WHEN campus_region = 'North East' THEN relmora_total_mg ELSE 0 END), sales_mid_atlantic = SUM(CASE WHEN campus_region = 'Mid Atlantic' THEN relmora_total_mg ELSE 0 END), sales_south_east = SUM(CASE WHEN campus_region = 'South East' THEN relmora_total_mg ELSE 0 END), sales_nation = SUM(relmora_total_mg). Coalesce nulls to 0 and cast/round to integers (no decimals)."
    }
  ],
  "group_by": [
    "week_end_date"
  ],
  "order_by": [
    {
      "column": "week_end_date",
      "direction": "ASC"
    }
  ],
  "limit": null,
  "final_output": {
    "columns": [
      "week_end_date",
      "sales_central",
      "sales_great_lakes",
      "sales_north_east",
      "sales_mid_atlantic",
      "sales_south_east",
      "sales_nation"
    ],
    "row_granularity": "per_group"
  },
  "validation_rules": [
    "Default time window to the most recent 52 weeks when not specified by the user.",
    "Derive MAX(week_end_date) from data_867 (do not use system date).",
    "Define the rolling 52-week window relative to MAX(week_end_date); include the max week and 51 prior weeks (inclusive).",
    "Use week_end_date for all weekly logic and filtering.",
    "Exclude records where relmora_total_mg <= 0.",
    "All sales outputs must be integers (no decimals); coalesce missing area values to 0 in pivoted columns.",
    "Compute area using campus_region because no area column exists in data_867; restrict area columns to the known campus_region values: 'Central', 'Great Lakes', 'North East', 'Mid Atlantic', 'South East'.",
    "sales_nation must equal the sum of the area columns for each week_end_date.",
    "Do not group by campus_id or parent_id; this is a geography trend request and should be aggregated nationally by geography."
  ],
  "rag_alignment": {
    "rag_provided": true,
    "used_examples": [
      "Example #1"
    ],
    "borrowed_patterns": [
      "Rolling 52-week window anchored to MAX(week_end_date)",
      "Weekly trend grouped by week_end_date with geography pivoted into separate columns plus a national total column",
      "Filter out non-positive sales volume rows and coalesce nulls to 0; output integer metrics"
    ],
    "differences_from_examples": [
      "Example uses an explicit area column with values ('West','East','Unknown'); data_867 does not have an area column, so area is mapped to campus_region and pivoted into the five known region values."
    ]
  }
}

