{
  "intent_summary": "Compute relmora sales contribution (%) by BC potential segment at the parent-account rollup over the most recent 52 weeks of available data, using national total relmora sales as the denominator, and return both absolute sales and contribution percent.",
  "tables": [
    "data_867"
  ],
  "filters": [
    {
      "column": "week_end_date",
      "operator": ">=",
      "value": "derived:rolling_window"
    },
    {
      "column": "week_end_date",
      "operator": "<=",
      "value": "derived:max_date"
    }
  ],
  "aggregations": [
    {
      "metric_name": "segment_sales_52w",
      "function": "SUM",
      "column": "relmora_total_mg",
      "group_level": "parent_id"
    },
    {
      "metric_name": "national_total_sales_52w",
      "function": "SUM",
      "column": "relmora_total_mg",
      "group_level": "none"
    }
  ],
  "subqueries": [
    {
      "name": "max_week_end_date_cte",
      "purpose": "Identify the most recent week_end_date in the dataset to anchor the rolling window",
      "logic": "Compute MAX(week_end_date) AS max_week_end_date from data_867"
    },
    {
      "name": "rolling_52w_start_cte",
      "purpose": "Determine the inclusive start week_end_date for the most recent 52-week window",
      "logic": "Derive start_week_end_date = (max_week_end_date - 51 weeks) from max_week_end_date_cte"
    },
    {
      "name": "windowed_base_cte",
      "purpose": "Filter rows to the most recent 52 weeks based on week_end_date",
      "logic": "Select rows from data_867 where week_end_date BETWEEN start_week_end_date AND max_week_end_date using the derived dates from prior CTEs"
    },
    {
      "name": "parent_sales_cte",
      "purpose": "Compute total relmora sales by parent account within the 52-week window",
      "logic": "From windowed_base_cte, group by parent_id, parent_account_name and compute SUM(relmora_total_mg) AS parent_sales_52w"
    },
    {
      "name": "national_total_cte",
      "purpose": "Compute national total relmora sales within the same 52-week window for contribution denominator",
      "logic": "From windowed_base_cte, compute SUM(relmora_total_mg) AS national_total_sales_52w"
    },
    {
      "name": "contribution_calc_cte",
      "purpose": "Calculate each parent account's contribution to national sales",
      "logic": "Cross join parent_sales_cte to national_total_cte and compute parent_contribution_52w = ROUND(100 * parent_sales_52w / NULLIF(national_total_sales_52w, 0), 0); if national_total_sales_52w is 0 then set parent_contribution_52w to 0; append '%' in final formatting"
    }
  ],
  "group_by": [
    "parent_id",
    "parent_account_name"
  ],
  "order_by": [
    {
      "column": "parent_contribution_52w",
      "direction": "DESC"
    },
    {
      "column": "parent_sales_52w",
      "direction": "DESC"
    },
    {
      "column": "parent_account_name",
      "direction": "ASC"
    }
  ],
  "limit": null,
  "final_output": {
    "columns": [
      "parent_id",
      "parent_account_name",
      "parent_sales_52w",
      "parent_contribution_52w"
    ],
    "row_granularity": "per_group"
  },
  "validation_rules": [
    "Use data_867 as the anchor table for sales.",
    "Because the user did not specify a time period, default to the most recent 52 weeks of available data.",
    "Determine the most recent period using MAX(week_end_date); do not use system date.",
    "Apply the rolling window relative to MAX(week_end_date) and make it inclusive of both endpoints (max_week_end_date - 51 weeks through max_week_end_date).",
    "Use relmora_total_mg (not relmora_total_sls) because the user asked about sales contribution without market share/competitor context per column selection rule.",
    "Denominator for contribution is overall national total sales (SUM(relmora_total_mg)) within the same 52-week window.",
    "Contribution values must be whole-number percentages (0 decimals), and the output must append '%' to contribution values.",
    "If national_total_sales_52w equals 0, set parent_contribution_52w to 0%.",
    "No time-period comparison was requested; do not compute growth and do not apply weekly-average normalization.",
    "All campus entities roll up to their respective parent entities; compute parent totals by grouping on parent_id and parent_account_name."
  ],
  "rag_alignment": {
    "rag_provided": true,
    "used_examples": [
      "Example #1"
    ],
    "borrowed_patterns": [
      "Default to most recent 52 weeks using MAX(week_end_date) and a derived rolling 52-week start date",
      "Compute segment/group sales and compute national total sales as denominator in separate CTEs",
      "Compute contribution percentage as 100 * group_sales / total_sales with divide-by-zero handling",
      "Order results by contribution percentage descending"
    ],
    "differences_from_examples": [
      "BC potential segment column is not present in data_867, so the grouping is done by parent_id and parent_account_name (parent account rollup) instead of by BC potential segment."
    ]
  }
}

{
  "intent_summary": "Compute relmora sales contribution by BC potential segment at the parent-account rollup level over the most recent rolling 52 weeks, using national total relmora sales as the denominator.",
  "tables": [
    "data_867"
  ],
  "filters": [
    {
      "column": "week_end_date",
      "operator": ">=",
      "value": "derived:rolling_window"
    },
    {
      "column": "week_end_date",
      "operator": "<=",
      "value": "derived:max_date"
    }
  ],
  "aggregations": [
    {
      "metric_name": "segment_sales_52w",
      "function": "SUM",
      "column": "relmora_total_mg",
      "group_level": "parent_account_name"
    },
    {
      "metric_name": "national_total_sales_52w",
      "function": "SUM",
      "column": "relmora_total_mg",
      "group_level": "none"
    }
  ],
  "subqueries": [
    {
      "name": "max_week_end_date_cte",
      "purpose": "Identify the most recent week_end_date in the dataset to anchor rolling windows.",
      "logic": "Compute MAX(week_end_date) from data_867."
    },
    {
      "name": "rolling_52w_start_cte",
      "purpose": "Derive the inclusive start of the most recent 52-week window.",
      "logic": "Compute start_week_end_date as (max_week_end_date - 51 weeks) to form a 52-week inclusive window ending on max_week_end_date."
    },
    {
      "name": "windowed_base_cte",
      "purpose": "Filter rows to the most recent rolling 52 weeks.",
      "logic": "Select rows from data_867 where week_end_date BETWEEN start_week_end_date AND max_week_end_date (inclusive)."
    },
    {
      "name": "segment_sales_cte",
      "purpose": "Aggregate relmora sales by parent and BC potential segment within the 52-week window.",
      "logic": "From windowed_base_cte, GROUP BY parent_id, parent_account_name, campus_tier and compute SUM(relmora_total_mg) as segment_sales_52w."
    },
    {
      "name": "national_total_cte",
      "purpose": "Compute national total relmora sales within the 52-week window to use as the contribution denominator.",
      "logic": "From windowed_base_cte, compute SUM(relmora_total_mg) as national_total_sales_52w."
    },
    {
      "name": "contribution_calc_cte",
      "purpose": "Calculate each parent x segment contribution to national sales.",
      "logic": "Join/CROSS JOIN segment_sales_cte with national_total_cte and compute contribution_52w = ROUND(100 * segment_sales_52w / NULLIF(national_total_sales_52w, 0), 0) as an integer; if national_total_sales_52w is 0 then set contribution_52w to 0. Append '%' to contribution_52w in final output."
    }
  ],
  "group_by": [
    "parent_id",
    "parent_account_name",
    "campus_tier"
  ],
  "order_by": [
    {
      "column": "contribution_52w",
      "direction": "DESC"
    },
    {
      "column": "segment_sales_52w",
      "direction": "DESC"
    }
